/**
 * Bundle Analyzer Engine
 *
 * Pure-function engine for analyzing Next.js bundle composition.
 * Detects: heavy imports that should be dynamic, barrel export issues,
 * duplicate dependencies, and generates optimization recommendations.
 *
 * @module bundle-analyzer
 */

// ─── Types ───────────────────────────────────────────────────────────

export type ImportRisk = 'critical' | 'high' | 'medium' | 'low';

export interface HeavyModule {
  name: string;
  pattern: RegExp;
  estimatedSizeKb: number;
  category: string;
  shouldBeDynamic: boolean;
}

export interface ImportInfo {
  filePath: string;
  importPath: string;
  lineNumber: number;
  isDynamic: boolean;
  isTypeOnly: boolean;
  rawLine: string;
}

export interface BundleIssue {
  risk: ImportRisk;
  category: string;
  filePath: string;
  importPath: string;
  lineNumber: number;
  message: string;
  suggestion: string;
  estimatedSizeKb: number;
}

export interface BarrelExportIssue {
  filePath: string;
  exportCount: number;
  reExportPaths: string[];
  message: string;
}

export interface BundleReport {
  generatedAt: string;
  totalFilesScanned: number;
  totalImports: number;
  issues: BundleIssue[];
  barrelIssues: BarrelExportIssue[];
  summary: BundleSummary;
  recommendations: string[];
}

export interface BundleSummary {
  criticalCount: number;
  highCount: number;
  mediumCount: number;
  lowCount: number;
  totalEstimatedWasteKb: number;
  heavyModulesFound: string[];
  dynamicImportCandidates: number;
  barrelExportIssues: number;
}

