// ─── Import Parsing ─────────────────────────────────────────────────

/**
 * Parse import statements from a TypeScript/JavaScript file content.
 */
export function parseImports(content: string, filePath: string): ImportInfo[] {
  const lines = content.split('\n');
  const imports: ImportInfo[] = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();

    // Skip comments
    if (trimmed.startsWith('//') || trimmed.startsWith('*') || trimmed.startsWith('/*')) continue;

    // Static imports: import X from 'path' or import { X } from 'path'
    const staticMatch = trimmed.match(/^import\s+(type\s+)?.*\s+from\s+['"]([^'"]+)['"]/);
    if (staticMatch) {
      imports.push({
        filePath,
        importPath: staticMatch[2],
        lineNumber: i + 1,
        isDynamic: false,
        isTypeOnly: !!staticMatch[1],
        rawLine: trimmed,
      });
      continue;
    }

    // Side-effect imports: import 'path'
    const sideEffectMatch = trimmed.match(/^import\s+['"]([^'"]+)['"]/);
    if (sideEffectMatch) {
      imports.push({
        filePath,
        importPath: sideEffectMatch[1],
        lineNumber: i + 1,
        isDynamic: false,
        isTypeOnly: false,
        rawLine: trimmed,
      });
      continue;
    }

    // Dynamic imports: import('path') or dynamic(() => import('path'))
    const dynamicMatches = trimmed.matchAll(/import\(\s*['"]([^'"]+)['"]\s*\)/g);
    for (const match of dynamicMatches) {
      imports.push({
        filePath,
        importPath: match[1],
        lineNumber: i + 1,
        isDynamic: true,
        isTypeOnly: false,
        rawLine: trimmed,
      });
    }

    // require() calls
    const requireMatch = trimmed.match(/require\(\s*['"]([^'"]+)['"]\s*\)/);
    if (requireMatch) {
      imports.push({
        filePath,
        importPath: requireMatch[1],
        lineNumber: i + 1,
        isDynamic: false,
        isTypeOnly: false,
        rawLine: trimmed,
      });
    }
  }

  return imports;
}

/**
 * Determine if a file is a server-side file (API route, server component, etc.)
 */
export function isServerFile(filePath: string): boolean {
  if (filePath.includes('/api/')) return true;
  if (filePath.includes('/server/')) return true;
  if (filePath.endsWith('.server.ts') || filePath.endsWith('.server.tsx')) return true;
  if (filePath.includes('/workers/') || filePath.includes('/scripts/')) return true;
  if (filePath.includes('/lib/queue/') || filePath.includes('/lib/database/')) return true;
  return false;
}

/**
 * Determine if a file is a client component.
 */
export function isClientFile(content: string): boolean {
  const firstLines = content.split('\n').slice(0, 5).join('\n');
  return firstLines.includes("'use client'") || firstLines.includes('"use client"');
}

// ─── Analysis ────────────────────────────────────────────────────────

/**
 * Find a matching heavy module for an import path.
 */
export function findHeavyModule(importPath: string): HeavyModule | null {
  return HEAVY_MODULES.find((m) => m.pattern.test(importPath)) || null;
}

/**
 * Determine the risk level for a non-dynamic heavy import.
 */
export function assessImportRisk(
  imp: ImportInfo,
  module: HeavyModule,
  isServer: boolean,
): ImportRisk {
  // Type-only imports are always safe
  if (imp.isTypeOnly) return 'low';

  // Dynamic imports are fine
  if (imp.isDynamic) return 'low';

  // 3D modules in client components are critical (should never be SSR)
  if (module.category === '3D' && !isServer) return 'critical';

  // Large modules (>300kb) that should be dynamic
  if (module.shouldBeDynamic && module.estimatedSizeKb > 300) return 'high';

  // Moderate modules that should be dynamic
  if (module.shouldBeDynamic) return 'medium';

  return 'low';
}

/**
 * Analyze imports for a single file and return issues.
 */
export function analyzeFileImports(
  content: string,
  filePath: string,
): BundleIssue[] {
  const imports = parseImports(content, filePath);
  const isServer = isServerFile(filePath);
  const issues: BundleIssue[] = [];

  for (const imp of imports) {
    // Skip relative imports and type imports
    if (imp.importPath.startsWith('.') || imp.importPath.startsWith('@/')) continue;
    if (imp.isTypeOnly) continue;

    const heavy = findHeavyModule(imp.importPath);
    if (!heavy) continue;

    const risk = assessImportRisk(imp, heavy, isServer);
    if (risk === 'low') continue;

    issues.push({
      risk,
      category: heavy.category,
      filePath: imp.filePath,
      importPath: imp.importPath,
      lineNumber: imp.lineNumber,
      message: `Static import of "${heavy.name}" (~${heavy.estimatedSizeKb}KB) — should use dynamic import`,
      suggestion: risk === 'critical'
        ? `Use next/dynamic: const ${capitalize(heavy.name)} = dynamic(() => import('${imp.importPath}'), { ssr: false })`
        : `Convert to dynamic import: const module = await import('${imp.importPath}')`,
      estimatedSizeKb: heavy.estimatedSizeKb,
    });
  }

  return issues;
}

/**
 * Capitalize the first letter of a string.
 */
export function capitalize(s: string): string {
  const clean = s.replace(/[^a-zA-Z]/g, '');
  return clean.charAt(0).toUpperCase() + clean.slice(1);
}

// ─── Barrel Export Detection ────────────────────────────────────────

/**
 * Detect barrel export files (index.ts that re-export everything).
 * These hurt tree-shaking because bundlers may include everything.
 */
export function detectBarrelExports(content: string, filePath: string): BarrelExportIssue | null {
  // Only check index.ts files
  if (!filePath.endsWith('/index.ts') && !filePath.endsWith('/index.tsx')) return null;

  const lines = content.split('\n');
  const reExports: string[] = [];
  let exportCount = 0;

  for (const line of lines) {
    const trimmed = line.trim();

    // export * from './module'
    const reExportMatch = trimmed.match(/^export\s+\*\s+from\s+['"]([^'"]+)['"]/);
    if (reExportMatch) {
      reExports.push(reExportMatch[1]);
      exportCount++;
      continue;
    }

    // export { X, Y } from './module'
    const namedReExport = trimmed.match(/^export\s+\{[^}]+\}\s+from\s+['"]([^'"]+)['"]/);
    if (namedReExport) {
      reExports.push(namedReExport[1]);
      exportCount++;
    }
  }

  // Only flag barrels with many re-exports
  if (exportCount >= 5) {
    return {
      filePath,
      exportCount,
      reExportPaths: reExports,
      message: `Barrel export with ${exportCount} re-exports may hurt tree-shaking`,
    };
  }

  return null;
}

// ─── Report Generation ───────────────────────────────────────────────

export interface FileEntry {
  path: string;
  content: string;
}

/**
 * Analyze a batch of files and generate a bundle report.
 */
export function generateBundleReport(files: FileEntry[]): BundleReport {
  const allIssues: BundleIssue[] = [];
  const barrelIssues: BarrelExportIssue[] = [];
  let totalImports = 0;

  for (const file of files) {
    const imports = parseImports(file.content, file.path);
    totalImports += imports.length;

    const issues = analyzeFileImports(file.content, file.path);
    allIssues.push(...issues);

    const barrel = detectBarrelExports(file.content, file.path);
    if (barrel) barrelIssues.push(barrel);
  }

  // Sort issues by risk (critical first)
  const riskOrder: Record<ImportRisk, number> = { critical: 0, high: 1, medium: 2, low: 3 };
  allIssues.sort((a, b) => riskOrder[a.risk] - riskOrder[b.risk]);

  const heavyModulesFound = [...new Set(allIssues.map((i) => i.importPath))];
  const totalWaste = allIssues.reduce((sum, i) => sum + i.estimatedSizeKb, 0);

  const summary: BundleSummary = {
    criticalCount: allIssues.filter((i) => i.risk === 'critical').length,
    highCount: allIssues.filter((i) => i.risk === 'high').length,
    mediumCount: allIssues.filter((i) => i.risk === 'medium').length,
    lowCount: allIssues.filter((i) => i.risk === 'low').length,
    totalEstimatedWasteKb: totalWaste,
    heavyModulesFound,
    dynamicImportCandidates: allIssues.filter((i) => i.risk !== 'low').length,
    barrelExportIssues: barrelIssues.length,
  };

  const recommendations = generateRecommendations(summary, allIssues, barrelIssues);

  return {
    generatedAt: new Date().toISOString(),
    totalFilesScanned: files.length,
    totalImports,
    issues: allIssues,
    barrelIssues,
    summary,
    recommendations,
  };
}

/**
 * Generate actionable recommendations from analysis.
 */
export function generateRecommendations(
  summary: BundleSummary,
  issues: BundleIssue[],
  barrelIssues: BarrelExportIssue[],
): string[] {
  const recs: string[] = [];

  if (summary.criticalCount > 0) {
    const critModules = [...new Set(issues.filter((i) => i.risk === 'critical').map((i) => i.importPath))];
    recs.push(
      `🚨 CRITICAL: Convert ${summary.criticalCount} static 3D imports to dynamic: ${critModules.join(', ')}. Use next/dynamic with { ssr: false }.`,
    );
  }

  if (summary.highCount > 0) {
    recs.push(
      `⚠️ HIGH: ${summary.highCount} heavy modules should use dynamic imports. Estimated savings: ~${Math.round(summary.totalEstimatedWasteKb)}KB.`,
    );
  }

  if (barrelIssues.length > 0) {
    recs.push(
      `📦 ${barrelIssues.length} barrel export files detected. Consider using direct imports instead of importing from index.ts.`,
    );
  }

  if (summary.totalEstimatedWasteKb > 500) {
    recs.push(
      `💡 Total estimated bundle waste: ~${Math.round(summary.totalEstimatedWasteKb)}KB. Code-splitting these modules would significantly improve initial load time.`,
    );
  }

  if (summary.dynamicImportCandidates === 0 && barrelIssues.length === 0) {
    recs.push('✅ No significant bundle optimization issues found. Good job!');
  }

  recs.push(
    '💡 Run `ANALYZE=true npx next build` to generate a detailed bundle visualization with @next/bundle-analyzer.',
  );

  return recs;
}

/**
 * Format a bundle report as human-readable text.
 */
export function formatBundleReportText(report: BundleReport): string {
  const lines: string[] = [];

  lines.push('═══════════════════════════════════════════════════════');
  lines.push('  NEXT.JS BUNDLE ANALYSIS REPORT');
  lines.push(`  Generated: ${report.generatedAt}`);
  lines.push('═══════════════════════════════════════════════════════');
  lines.push('');

  lines.push('📊 SUMMARY');
  lines.push(`  Files scanned: ${report.totalFilesScanned}`);
  lines.push(`  Total imports: ${report.totalImports}`);
  lines.push(`  Estimated waste: ~${Math.round(report.summary.totalEstimatedWasteKb)}KB`);
  lines.push('');

  lines.push('🔍 ISSUES');
  lines.push(`  🚨 Critical: ${report.summary.criticalCount}`);
  lines.push(`  ⚠️  High: ${report.summary.highCount}`);
  lines.push(`  📦 Medium: ${report.summary.mediumCount}`);
  lines.push(`  ℹ️  Low: ${report.summary.lowCount}`);
  lines.push(`  📁 Barrel exports: ${report.summary.barrelExportIssues}`);
  lines.push('');

  if (report.issues.length > 0) {
    lines.push('── IMPORT ISSUES ──');
    for (const issue of report.issues) {
      const icon = issue.risk === 'critical' ? '🚨' : issue.risk === 'high' ? '⚠️' : '📦';
      lines.push(`  ${icon} [${issue.risk.toUpperCase()}] ${issue.filePath}:${issue.lineNumber}`);
      lines.push(`     ${issue.message}`);
      lines.push(`     → ${issue.suggestion}`);
    }
    lines.push('');
  }

  if (report.barrelIssues.length > 0) {
    lines.push('── BARREL EXPORT ISSUES ──');
    for (const bi of report.barrelIssues) {
      lines.push(`  📁 ${bi.filePath} — ${bi.exportCount} re-exports`);
      lines.push(`     ${bi.message}`);
    }
    lines.push('');
  }

  lines.push('📝 RECOMMENDATIONS');
  for (const rec of report.recommendations) {
    lines.push(`  ${rec}`);
  }
  lines.push('');

  return lines.join('\n');
}
